import{c as t,Q as a,j as o,m as n}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"WeChat Official Account Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/wechatoa.md","filePath":"channels/wechatoa.md","lastUpdated":1776332711000}'),i={name:"channels/wechatoa.md"};function r(l,e,s,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="wechat-official-account-channel-configuration" tabindex="-1">WeChat Official Account Channel Configuration <a class="header-anchor" href="#wechat-official-account-channel-configuration" aria-label="Permalink to &quot;WeChat Official Account Channel Configuration&quot;">​</a></h1><p>This guide covers the <strong>WeChat Official Account</strong> adapter in Memoh. It is different from the personal <strong>WeChat</strong> QR-login adapter: this one is for official-account webhook integration and is intended for inbound private-message scenarios.</p><h2 id="step-1-prepare-official-account-credentials" tabindex="-1">Step 1: Prepare Official Account Credentials <a class="header-anchor" href="#step-1-prepare-official-account-credentials" aria-label="Permalink to &quot;Step 1: Prepare Official Account Credentials&quot;">​</a></h2><p>From the WeChat Official Account platform, prepare:</p><ul><li><strong>App ID</strong></li><li><strong>App Secret</strong></li><li><strong>Token</strong></li></ul><p>You may also need:</p><ul><li><strong>Encoding AES Key</strong> if you use encrypted webhook delivery</li><li>an outbound <strong>HTTP Proxy URL</strong> if your deployment must reach WeChat APIs through a proxy</li></ul><h2 id="step-2-add-the-channel-in-memoh" tabindex="-1">Step 2: Add The Channel In Memoh <a class="header-anchor" href="#step-2-add-the-channel-in-memoh" aria-label="Permalink to &quot;Step 2: Add The Channel In Memoh&quot;">​</a></h2><ol><li>Open your bot in the Memoh Web UI.</li><li>Go to <strong>Platforms</strong>.</li><li>Click <strong>Add Channel</strong> and choose <strong>WeChat Official Account</strong>.</li><li>Fill in the required fields: <ul><li><strong>App ID</strong></li><li><strong>App Secret</strong></li><li><strong>Token</strong></li></ul></li><li>Choose the <strong>Encryption Mode</strong>.</li><li>If you use <code>safe</code> or <code>compat</code> mode, also provide the <strong>Encoding AES Key</strong>.</li><li>Save the channel.</li></ol><p>Memoh generates a <strong>Webhook Callback URL</strong> after the channel has been saved.</p><h2 id="step-3-configure-the-wechat-platform" tabindex="-1">Step 3: Configure The WeChat Platform <a class="header-anchor" href="#step-3-configure-the-wechat-platform" aria-label="Permalink to &quot;Step 3: Configure The WeChat Platform&quot;">​</a></h2><ol><li>Copy the <strong>Webhook Callback URL</strong> from Memoh.</li><li>Paste it into the WeChat Official Account platform callback configuration.</li><li>Make sure the WeChat platform and Memoh use the same: <ul><li><strong>Token</strong></li><li><strong>Encryption Mode</strong></li><li><strong>Encoding AES Key</strong> when encryption is enabled</li></ul></li></ol><p>WeChat will verify the callback before delivering real messages.</p><h2 id="step-4-enable-and-test" tabindex="-1">Step 4: Enable And Test <a class="header-anchor" href="#step-4-enable-and-test" aria-label="Permalink to &quot;Step 4: Enable And Test&quot;">​</a></h2><ol><li>Enable the channel in Memoh.</li><li>Send a test private message from the official account side.</li><li>Confirm that Memoh receives the message and the bot can reply.</li></ol><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Private chats</strong></li><li><strong>Replies</strong></li><li><strong>Attachments and media</strong></li></ul><p>Current behavior notes:</p><ul><li>This adapter is intended for <strong>private-message</strong> conversations, not group-style chats.</li><li>Outbound responses are non-streaming on this channel.</li></ul>',19)])])}const f=t(i,[["render",r]]);export{u as __pageData,f as default};
